from dataclasses import dataclass

@dataclass
class Triple:
    subject: str
    predicate: str
    object: str

# EVOLVE-BLOCK-START

def predict(triples: list[Triple]) -> str:
    """
    Convert a list of triples about astronauts (or related entities) into a
    fluent English sentence.  The function groups triples by their subject and
    builds a clause for each predicate, then joins the clauses into a single
    (or a few) readable sentences.
    """
    if not triples:
        return ""

    # Helper to turn a predicate/object pair into a descriptor (without repeating the subject)
    def phrase(subj: str, pred: str, obj: str) -> str:
        """Return a natural‑language descriptor for a single predicate."""
        obj = obj.strip().strip('"')
        p = pred.lower().replace(" ", "")
        def fmt_date(d: str) -> str:
            try:
                from datetime import datetime
                dt = datetime.strptime(d, "%Y-%m-%d")
                return dt.strftime("%B %-d, %Y")
            except Exception:
                return d

        if p == "birthdate":
            return f"was born on {fmt_date(obj)}"
        if p == "birthplace":
            return f"was born in {obj}"
        if p == "deathdate":
            return f"died on {fmt_date(obj)}"
        if p == "deathplace":
            return f"died in {obj}"
        if p == "nationality":
            # Prefer a natural phrasing using "from" or "a citizen of"
            low_obj = obj.lower()
            if low_obj in ("united states", "usa", "united states of america"):
                phr = "American"
                return f"is {phr}"
            else:
                return f"is from {obj}"
        if p == "occupation":
            return f"was a {obj.lower()}"
        if p == "status":
            low = obj.lower()
            if low == "retired":
                return "is retired"
            return f"is {low}"
        if p == "selectedbynasa":
            return f"was selected by NASA in {obj}"
        if p == "mission":
            # Assume subject is an astronaut; describe crew membership in the mission
            return f"was a crew member of {obj}"
        if p == "timeinspace":
            try:
                mins = float(obj)
                hrs = int(mins // 60)
                rem = int(mins % 60)
                if hrs:
                    return f"spent {hrs} hour{'s' if hrs>1 else ''}" + (f" and {rem} minute{'s' if rem!=1 else ''}" if rem else "") + " in space"
                else:
                    return f"spent {rem} minute{'s' if rem!=1 else ''} in space"
            except Exception:
                return f"spent {obj} minutes in space"
        if p == "title":
            return f"held the title of {obj}"
        if p == "award":
            return f"received the {obj}"
        if p == "awards":
            return f"received {obj} awards"
        if p == "ribbonaward":
            return f"was awarded the {obj}"
        if p == "operator":
            return f"operated by {obj}"
        if p == "commander":
            # For mission subjects, express role succinctly
            return f"commander {obj}"
        if p == "backuppilot":
            # Return a full sentence to avoid double‑subject in final output
            return "__FULL__" + f"{obj} was the backup pilot on {subj}"
        if p == "crewmembers":
            return f"crew member {obj}"
        if p == "leader":
            # Subject is an entity, object is a person
            return f"{obj} is the leader of {subj}"
        if p == "representative":
            return f"{obj} was the representative of {subj}"
        if p == "alternativename":
            return f"is also known as {obj}"
        if p == "servedaschiefoftheastronautofficein":
            return f"served as Chief of the Astronaut Office in {obj}"
        if p == "bird":
            return f"The {obj.lower()} is a bird found in {subj}"
        # New handling for geographic part relationships
        if p == "part":
            # Expect format "X County, State" or similar
            parts = [x.strip() for x in obj.split(',')]
            if len(parts) == 2:
                typ = parts[0]
                loc = parts[1]
                return f"is a {typ.lower()} in {loc}"
            else:
                return f"is part of {obj}"
        if p == "partstype":
            # This predicate provides type information that is usually redundant with 'part'
            # Skip generating a separate clause
            return ""
        # Generic fallback
        return f"is {obj}"

    # Group triples by subject
    from collections import defaultdict
    groups = defaultdict(list)
    for t in triples:
        groups[t.subject].append(t)

    sentences = []
    for subj, items in groups.items():
        subject_phrase = subj
        # Build sentences, handling possible full‑sentence descriptors
        partials = []
        for t in items:
            desc = phrase(subj, t.predicate, t.object)
            if desc.startswith("__FULL__"):
                # Strip marker and add as independent sentence
                sentences.append(desc[len("__FULL__"):].rstrip('.') + ".")
            else:
                partials.append(desc)
        if not partials:
            # Only full‑sentence descriptors were added, or no descriptors at all
            continue
        if len(partials) == 1:
            sent = f"{subject_phrase} {partials[0]}."
        elif len(partials) == 2:
            sent = f"{subject_phrase} {partials[0]} and {partials[1]}."
        else:
            body = ", ".join(partials[:-1])
            sent = f"{subject_phrase} {body}, and {partials[-1]}."
        sentences.append(sent)

    # Combine sentences for different subjects
    return " ".join(sentences)

# EVOLVE-BLOCK-END
